int** allocate_image(int width, int height) {
    int** image = (int**)malloc(height * sizeof(int*));
    if (image == NULL) {
        return NULL;
    }
    
    for (int i = 0; i < height; i++) {
        image[i] = (int*)malloc(width * sizeof(int));
        if (image[i] == NULL) {
            // Free previously allocated memory
            for (int j = 0; j < i; j++) {
                free(image[j]);
            }
            free(image);
            return NULL;
        }
    }
    
    return image;
}